INSERT INTO TCF_JWT_LOGIN_HISTORY (
    LOG_ID, USER_ID, LOGIN_RESULT, FAIL_REASON, CHANNEL_ID, CLIENT_IP, LOGIN_TIME
) VALUES (
    #{logId}, #{userId}, #{loginResult}, #{failReason}, #{channelId}, #{clientIp}, #{loginTime}
)

MERGE INTO TCF_JWT_SECURITY_POLICY (
    POLICY_ID, ISSUER, AUDIENCE, ACCESS_TOKEN_VALID_MINUTES, REFRESH_TOKEN_VALID_HOURS,
    ALGORITHM, CLOCK_SKEW_SECONDS, DENYLIST_CHECK_ENABLED, REFRESH_TOKEN_ROTATION_ENABLED,
    UPDATED_AT, UPDATED_BY
) KEY (POLICY_ID) VALUES (
    #{policyId}, #{issuer}, #{audience}, #{accessTokenValidMinutes}, #{refreshTokenValidHours},
    #{algorithm}, #{clockSkewSeconds}, #{denylistCheckEnabled}, #{refreshTokenRotationEnabled},
    #{updatedAt}, #{updatedBy}
)
